import{_ as a,o as i,c as t,ao as o}from"./chunks/framework.Cdz4zV7J.js";const h=JSON.parse('{"title":"Audience And Comparators","description":"","frontmatter":{},"headers":[],"relativePath":"audience-comparators.md","filePath":"audience-comparators.md","lastUpdated":null}'),r={name:"audience-comparators.md"};function n(s,e,d,l,p,c){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="Audience-And-Comparators" tabindex="-1">Audience And Comparators <a class="header-anchor" href="#Audience-And-Comparators" aria-label="Permalink to &quot;Audience And Comparators {#Audience-And-Comparators}&quot;">​</a></h1><p><code>HSquared.jl</code> is being built for people who need quantitative-genetic models to work on real breeding and evolutionary data.</p><h2 id="Who-It-Is-For" tabindex="-1">Who It Is For <a class="header-anchor" href="#Who-It-Is-For" aria-label="Permalink to &quot;Who It Is For {#Who-It-Is-For}&quot;">​</a></h2><ul><li><p>livestock and aquaculture breeders;</p></li><li><p>plant breeders;</p></li><li><p>evolutionary geneticists;</p></li><li><p>ecological quantitative geneticists;</p></li><li><p>genomic prediction users;</p></li><li><p>applied students and analysts who need readable errors and extractors.</p></li></ul><h2 id="What-They-Need" tabindex="-1">What They Need <a class="header-anchor" href="#What-They-Need" aria-label="Permalink to &quot;What They Need {#What-They-Need}&quot;">​</a></h2><p>The package should make common work straightforward:</p><ul><li><p>fit pedigree and genomic animal models from R;</p></li><li><p>construct relationship precision matrices without hidden dense conversions;</p></li><li><p>extract breeding values, variance components, heritability, genetic correlations, G matrices, and uncertainty;</p></li><li><p>compare models with diagnostics that distinguish weak evidence from software failure;</p></li><li><p>move from R syntax to a Julia engine through a bridge.</p></li></ul><h2 id="Comparator-Discipline" tabindex="-1">Comparator Discipline <a class="header-anchor" href="#Comparator-Discipline" aria-label="Permalink to &quot;Comparator Discipline {#Comparator-Discipline}&quot;">​</a></h2><p><code>HSquared.jl</code> should be tested against the software users already trust: ASReml, BLUPF90, DMU, WOMBAT, sommer, MCMCglmm, JWAS, AGHmatrix, nadiv, and XSim-based simulations where appropriate.</p><p>The ambition is to become a free, open, benchmarked engine for pedigree, genomic, livestock, plant-breeding, and evolutionary quantitative genetics. That is a roadmap goal. It is not yet a benchmark claim.</p><p>Any public speed or superiority claim must report the machine, software versions, model, data size, number of records, animals, traits, nonzeros, memory use, convergence diagnostics, and the exact comparator estimand.</p>',11)])])}const u=a(r,[["render",n]]);export{h as __pageData,u as default};
